mapper.insert:
insert into tbl_member (
    email, password, nickname, role, status, created_datetime, updated_datetime
) values (
    #{email}, #{password}, #{nickname}, #{role}, #{status}, now(), now()
)

mapper.select:
select id
from tbl_member
where email = #{email}

select w.id, w.member_id, w.title, w.category, w.is_tradable, w.price, w.status, m.nickname as member_nickname, m.profile_image as member_profile_image, t_file.file_url as thumbnail_url, t_file.file_type as thumbnail_file_type, t_file.width as thumbnail_width, t_file.height as thumbnail_height, w.view_count, w.like_count, w.save_count, w.comment_count, w.created_datetime from tbl_work w left join tbl_member m on w.member_id = m.id left join lateral ( select wf.file_url, wf.file_type, wf.width, wf.height from tbl_work_file wf where wf.work_id = w.id order by wf.sort_order asc, wf.id asc limit 1 ) t_file on true where w.deleted_datetime is null and w.status != 'DELETED'
and exists ( select 1 from tbl_gallery_work gw where gw.work_id = w.id and gw.gallery_id = #{galleryId} )
and ( w.title ilike '%' || #{keyword} || '%' or w.description ilike '%' || #{keyword} || '%' or m.nickname ilike '%' || #{keyword} || '%' )
and w.category = #{category}
and w.member_id = #{memberId}
and w.license_type = #{licenseType}
and w.is_tradable = #{isTradable}
and w.allow_comment = #{allowComment}
and w.show_similar = #{showSimilar}
and w.status = #{status}
order by w.created_datetime desc limit #{size} offset (#{page} - 1) * #{size}

select count(*)
from tbl_work w
left join tbl_member m on w.member_id = m.id
where w.deleted_datetime is null
  and w.status != 'DELETED'

    and exists (
        select 1
        from tbl_gallery_work gw
        where gw.work_id = w.id
          and gw.gallery_id = #{galleryId}
    )


    and (
        w.title ilike '%' || #{keyword} || '%'
        or w.description ilike '%' || #{keyword} || '%'
        or m.nickname ilike '%' || #{keyword} || '%'
    )


    and w.category = #{category}


    and w.member_id = #{memberId}


    and w.license_type = #{licenseType}


    and w.is_tradable = #{isTradable}


    and w.allow_comment = #{allowComment}


    and w.show_similar = #{showSimilar}


    and w.status = #{status}

mapper.insert:
insert into tbl_work_file (
    work_id, file_url, file_type, file_size, width, height, sort_order
) values (
    #{workId}, #{fileUrl}, #{fileType}, #{fileSize}, #{width}, #{height}, coalesce(#{sortOrder}, 0)
)

insert into tbl_work_tag (
    work_id, tag_id
) values (
    #{workId}, #{tagId}
)

mapper.select:
select id
from tbl_tag
where tag_name = #{tagName}

mapper.insert:
insert into tbl_comment (
    member_id, target_type, target_id, parent_id, content, is_pinned, like_count
) values (
    #{memberId}, #{targetType}, #{targetId}, #{parentId}, #{content}, coalesce(#{isPinned}, false), coalesce(#{likeCount}, 0)
)

mapper.select:
select exists (
    select 1
    from tbl_work_like
    where member_id = #{memberId}
      and work_id = #{workId}
)

mapper.insert:
insert into tbl_work_like (
    member_id, work_id
) values (
    #{memberId}, #{workId}
)

mapper.delete:
delete from tbl_work_like
where member_id = #{memberId}
  and work_id = #{workId}
